# Test the gate_status merge reducer behavior

from src.state import HCGRCState, initial_state

state = initial_state()

# Simulate merging two gate updates
update1 = {
    "gate_status": {
        "gate_1": {
            "gate_id": "gate_1",
            "decision": "approved",
            "rationale": "OK",
            "reviewer": "operator",
            "timestamp_utc": "2026-06-15T00:00:00Z",
            "run_id": "test"
        }
    }
}

update2 = {
    "gate_status": {
        "gate_2": {
            "gate_id": "gate_2",
            "decision": "deferred",
            "rationale": "OK",
            "reviewer": "operator",
            "timestamp_utc": "2026-06-15T00:01:00Z",
            "run_id": "test"
        }
    }
}

# Apply updates using the merge reducer
gate_status = state["gate_status"]
gate_status = {**gate_status, **update1["gate_status"]}  # This simulates the merge reducer
print(f"After update1: {list(gate_status.keys())}")

gate_status = {**gate_status, **update2["gate_status"]}  # Merge update2
print(f"After update2: {list(gate_status.keys())}")

# Check if both gates are present
if "gate_1" in gate_status and "gate_2" in gate_status:
    print("✓ Merge reducer correctly combines updates")
    print(f"  gate_1: {gate_status['gate_1']['decision']}")
    print(f"  gate_2: {gate_status['gate_2']['decision']}")
else:
    print("✗ Merge reducer failed")

# Test collision: two updates for same gate
update3 = {
    "gate_status": {
        "gate_1": {
            "gate_id": "gate_1",
            "decision": "rejected",  # Different decision
            "rationale": "New",
            "reviewer": "operator",
            "timestamp_utc": "2026-06-15T00:02:00Z",
            "run_id": "test"
        }
    }
}

gate_status = {**gate_status, **update3["gate_status"]}
print(f"\nAfter update3 (collision on gate_1):")
print(f"  gate_1 decision: {gate_status['gate_1']['decision']} (should be 'rejected')")
if gate_status['gate_1']['decision'] == 'rejected':
    print("✓ Last-write-wins merge works correctly")
else:
    print("✗ Merge failed")

EOF
